/**
 * Reshape PG row → S-02 input shape.
 * S-02 expects: { text, tableBlocks, metadata }
 * PG `content` is already the assembled OCR text (S-02 will rebuild content from it).
 * PG `metadata` JSONB is camelCase and matches S-02's expected metadata.
 */
return $input.all().map(item => {
  const d = item.json;
  const meta = d.metadata || {};
  // Ensure required defaults
  meta.workflowVersion = 'v5-phase-b-v2-backfill';
  return {
    json: {
      text: d.content || '',
      tableBlocks: Array.isArray(d.table_blocks) ? d.table_blocks : [],
      metadata: meta,
      _backfill: {
        internal_number: d.internal_number,
        old_collection: d.old_collection
      }
    }
  };
});

/**
 * Aggregate per-doc result for the run summary.
 */
const results = $input.all().map(item => {
  const j = item.json || {};
  return {
    internal_number: j.internalNumber || j._backfill?.internal_number || null,
    success: j.success === true,
    chunks: j.chunksIngested || 0,
    strategy: j.strategy || null,
    collection: j.collection || null,
    error: j.error || j.postgresError || null
  };
});
const summary = {
  total: results.length,
  succeeded: results.filter(r => r.success).length,
  failed: results.filter(r => !r.success).length,
  total_chunks: results.reduce((s, r) => s + (r.chunks || 0), 0)
};
return [{ json: { summary, results } }];
